def is_link_or_reparse(file_stat: os.stat_result) -> bool:
    return stat.S_ISLNK(file_stat.st_mode) or bool(
        getattr(file_stat, "st_file_attributes", 0) & REPARSE_POINT_ATTRIBUTE
    )


def read(path: Path) -> str:
    resolved = path.resolve()
    try:
        resolved.relative_to(ROOT)
    except ValueError as exc:
        raise AssertionError(f"source-contract read escaped repository root: {path}") from exc
    try:
        file_stat = path.lstat()
    except FileNotFoundError as exc:
        raise AssertionError(f"source-contract input is missing: {path}") from exc
    if is_link_or_reparse(file_stat) or not stat.S_ISREG(file_stat.st_mode):
        raise AssertionError(f"source-contract input must be a regular non-linked file: {path}")
    if file_stat.st_size > MAX_SOURCE_CONTRACT_FILE_BYTES:
        raise AssertionError(
            f"source-contract input exceeds {MAX_SOURCE_CONTRACT_FILE_BYTES} bytes: {path}"
        )
    return path.read_text(encoding="utf-8", errors="ignore")


def test_source_contract_read_helper_bounds_source_files():
    source = read(Path(__file__))
    helper_start = source.index("def is_link_or_reparse")
    helper_end = source.index("def test_source_contract_read_helper_bounds_source_files")
    helper_source = source[helper_start:helper_end]

    assert "MAX_SOURCE_CONTRACT_FILE_BYTES = 8 * 1024 * 1024" in source
    assert "REPARSE_POINT_ATTRIBUTE" in source
    assert "resolved.relative_to(ROOT)" in helper_source
    assert "path.lstat()" in helper_source
    assert "stat.S_ISREG(file_stat.st_mode)" in helper_source
    assert "file_stat.st_size > MAX_SOURCE_CONTRACT_FILE_BYTES" in helper_source
    assert 'path.read_text(encoding="utf-8", errors="ignore")' in helper_source


