def test_home_protected_status_requires_ready_engine_evidence():
    home = read(HOME_SCREEN)
    main_start = home.index("String _mainStatus")
    headline_start = home.index("String _headline")
    main_status = home[main_start:headline_start]
    hero_start = home.index("String _heroCopy")
    color_start = home.index("Color _mainColor")
    hero_copy = home[hero_start:color_start]
    metric_start = home.index("String _realTimeProtectionValue")
    metric_helpers = home[metric_start:headline_start]
    native_engine_helpers = home[
        home.index("String _nativeEngineLabel"):
        home.index("String _guardLabel")
    ]

    assert "if (_engineNeedsAttention(state))" in main_status
    assert "state.malwareEngineStatus != MalwareEngineStatus.available" in home
    assert "state.nativeEngineStatus != 'ready'" in home
    assert "state.lastEngineError?.trim().isNotEmpty ?? false" in home
    assert main_status.index("if (_engineNeedsAttention(state))") < main_status.index(
        "state.protectionStatus == ProtectionStatus.protected"
    )
    assert "value: _realTimeProtectionValue(state)" in home
    assert "detail: _realTimeProtectionDetail(state)" in home
    assert "if (_engineNeedsAttention(state)) return 'Attention needed'" in metric_helpers
    assert "value: _nativeEngineLabel(state)" in home
    assert "detail: _nativeEngineDetail(state)" in home
    assert "state.lastEngineError?.trim().isNotEmpty ?? false" in native_engine_helpers
    assert "return 'Attention needed'" in native_engine_helpers
    assert "Engine diagnostic: $diagnostic" in native_engine_helpers
    assert native_engine_helpers.index("lastEngineError") < native_engine_helpers.index(
        "state.nativeEngineStatus"
    )
    assert "ProtectionStatus.partiallyProtected" in metric_helpers
    assert "return 'Limited'" in metric_helpers
    assert hero_copy.index("if (status == 'Attention needed')") < hero_copy.index(
        "state.protectionStatus == ProtectionStatus.localOnly"
    )


