def test_flutter_pack_count_labels_are_status_aware():
    home = read(HOME_SCREEN)
    protection = read(PROTECTION_SCREEN)
    settings = read(SETTINGS_SCREEN)
    settings_test = read(ROOT / "apps" / "zentor_client" / "test" / "settings_accessibility_test.dart")

    home_helper = home[
        home.index("String _nativeRuleCountLabel"):
        home.index("String _updateDetail")
    ]
    protection_helpers = protection[
        protection.index("String _nativeRuleCountLabel"):
        protection.index("String _watcherLabel")
    ]
    settings_helper = settings[
        settings.index("String _nativePackagedCountLabel"):
        settings.index("String _guardLabel")
    ]

    assert "value: _nativeRuleCountLabel(state)" in home
    assert "final engineDiagnosticVisible" in home_helper
    assert "state.lastEngineError?.trim().isNotEmpty ?? false" in home_helper
    assert "state.nativeEngineStatus == 'ready' && !engineDiagnosticVisible" in home_helper
    assert home_helper.index("final engineDiagnosticVisible") < home_helper.index(
        "state.nativeEngineStatus == 'ready' && !engineDiagnosticVisible"
    )
    assert "return 'Unknown';" in home_helper
    assert "value: _nativeRuleCountLabel(state)" in protection
    assert "_nativePackCountLabel(" in protection
    assert "count: state.nativeSignatureCount" in protection
    assert "count: state.nativeRuleCount" in protection
    assert "state: state" in protection
    assert "final engineDiagnosticVisible" in protection_helpers
    assert "state.lastEngineError?.trim().isNotEmpty ?? false" in protection_helpers
    assert protection_helpers.count(
        "state.nativeEngineStatus == 'ready' && !engineDiagnosticVisible"
    ) >= 2
    assert "return 'Unknown';" in protection_helpers
    assert "_nativePackagedCountLabel(" in settings
    assert "count: state.nativeSignatureCount" in settings
    assert "count: state.nativeRuleCount" in settings
    assert "state: state" in settings
    assert "final engineDiagnosticVisible" in settings_helper
    assert "state.lastEngineError?.trim().isNotEmpty ?? false" in settings_helper
    assert "state.nativeEngineStatus == 'ready' && !engineDiagnosticVisible" in settings_helper
    assert "return 'Unknown';" in settings_helper
    assert "_CheckRow('Signature Pack', '${state.nativeSignatureCount} loaded')" not in protection
    assert "_CheckRow('Rule Pack', '${state.nativeRuleCount} loaded')" not in protection
    assert "'${state.nativeSignatureCount} packaged signatures loaded'" not in settings
    assert "'${state.nativeRuleCount} packaged rules loaded'" not in settings
    assert "pack count labels stay unknown until native engine readiness is proven" in settings_test
    assert "pack count labels can show zero only with ready native engine evidence" in settings_test
    assert "expect(find.text('0 rules loaded'), findsNothing)" in settings_test
    assert "expect(find.text('0 packaged signatures loaded'), findsNothing)" in settings_test
    assert "expect(find.text('0 packaged rules loaded'), findsNothing)" in settings_test


