def test_flutter_protection_native_engine_checklist_distinguishes_unavailable():
    protection = read(PROTECTION_SCREEN)
    settings_test = read(ROOT / "apps" / "zentor_client" / "test" / "settings_accessibility_test.dart")
    helper = protection[
        protection.index("String _nativeEngineChecklistLabel"):
        protection.index("String _nativeRuleCountLabel")
    ]

    assert "_nativeEngineChecklistLabel(state)" in protection
    assert "state.nativeEngineStatus == 'ready' ? 'Ready' : 'Error'" not in protection
    assert "state.nativeEngineStatus == 'ready'\n                    ? 'Ready'\n                    : 'Unavailable'" not in protection
    assert "state.lastEngineError?.trim().isNotEmpty ?? false" in helper
    assert "return 'Attention needed'" in helper
    assert helper.index("lastEngineError") < helper.index("state.nativeEngineStatus")
    assert "'ready' => 'Ready'" in helper
    assert "'error' => 'Error'" in helper
    assert "'unavailable' => 'Unavailable'" in helper
    assert "_ => 'Unknown'" in helper
    assert "native engine status labels distinguish ready error unavailable and unknown" in settings_test
    assert "native engine diagnostics override ready status labels" in settings_test
    assert "protection native engine checklist renders unavailable distinctly" in settings_test
    assert "const ZentorState(nativeEngineStatus: 'unavailable')" in settings_test


