    for screen_path in [HOME_SCREEN, DEVICE_SCREEN]:
        source = read(screen_path)
        metric = source[
            source.index("title: 'Avorax Native Engine'"):
            source.index("String _nativeEngineLabel")
        ]
        helper = source[
            source.index("String _nativeEngineLabel"):
            source.index("String _", source.index("String _nativeEngineLabel") + 1)
        ]

        assert "value: _nativeEngineLabel(state)" in metric
        assert "state.lastEngineError?.trim().isNotEmpty ?? false" in helper
        assert "return 'Attention needed'" in helper
        assert "String _nativeEngineDetail(ZentorState state)" in source
        if screen_path == DEVICE_SCREEN:
            detail = source[
                source.index("String _nativeEngineDetail"):
                source.index("String _serviceDetails")
            ]
            assert "final diagnostic = state.lastEngineError?.trim()" in detail
            assert "Engine diagnostic: $diagnostic" in detail
        assert "state.nativeEngineStatus == 'ready' ? 'Ready' : 'Unavailable'" not in metric
        assert "'ready' => 'Ready'" in helper
        assert "'error' => 'Error'" in helper
        assert "'unavailable' => 'Unavailable'" in helper
        assert "_ => 'Unknown'" in helper
    assert "await _pumpDeviceScreenWithState(tester, state)" in settings_test
    assert "expect(find.text(entry.value), findsWidgets)" in settings_test


