def test_flutter_native_ml_labels_match_allowed_health_statuses():
    settings_test = read(ROOT / "apps" / "zentor_client" / "test" / "settings_accessibility_test.dart")
    scan_test = read(ROOT / "apps" / "zentor_client" / "test" / "scan_screen_test.dart")
    for screen_path in [HOME_SCREEN, PROTECTION_SCREEN, SETTINGS_SCREEN, DEVICE_SCREEN]:
        source = read(screen_path)
        helper_name = (
            "String _nativeMlLabel"
            if screen_path in [HOME_SCREEN, SETTINGS_SCREEN]
            else "String _localAiLabel"
            if screen_path == PROTECTION_SCREEN
            else "String _mlLabel"
        )
        helper_start = source.index(helper_name)
        helper_end = source.find("\nString _", helper_start + len(helper_name))
        if helper_end == -1:
            helper_end = len(source)
        helper = source[
            helper_start:
            helper_end
        ]

        if screen_path == PROTECTION_SCREEN:
            assert "AiModelStatus.active => 'Active'" in helper
            assert "AiModelStatus.developmentModel" in helper
            assert "AiModelStatus.modelMissing => 'Missing'" in helper
            assert "AiModelStatus.error => 'Error'" in helper
        else:
            assert "'loaded' => 'Loaded'" in helper
            assert "'developmentModel'" in helper
            assert "'modelMissing' => 'Missing'" in helper
            assert "'error' => 'Error'" in helper
        assert "'active' => 'Production'" not in helper
    scan = read(SCAN_SCREEN)
    scan_helper = scan[
        scan.index("String _nativeMlAssetLabel"):
        scan.index("class _DiagnosticChip")
    ]
    assert "value: _nativeMlAssetLabel(state.nativeMlStatus)" in scan
    assert "'loaded' => 'Found'" in scan_helper
    assert "'developmentModel' => 'Found (development)'" in scan_helper
    assert "'modelMissing' => 'Missing'" in scan_helper
    assert "'error' => 'Error'" in scan_helper
    assert "_ => 'Unknown'" in scan_helper
    assert "_ValueRow('Model status', _nativeMlLabel(state.nativeMlStatus))" in read(SETTINGS_SCREEN)
    assert "value: _nativeMlLabel(state.nativeMlStatus)" in read(HOME_SCREEN)
    assert "native ml status labels distinguish allowed health statuses" in settings_test
    assert "protection local ai labels distinguish ai statuses" in settings_test
    assert "scan engine diagnostics distinguish native ml status labels" in scan_test
    assert "ML model: ${entry.value}" in scan_test


def test_native_ml_status_and_provider_inventory_use_production_ready_metadata():
    local_core = read(LOCAL_CORE_MAIN)
    native_engine = read(NATIVE_ENGINE)
    provider = read(NATIVE_DETECTION_PROVIDER)
    status_struct = native_engine[
        native_engine.index("pub struct EngineStatus"):
        native_engine.index("pub struct SelfTestReport")
    ]
    status_fn = native_engine[
        native_engine.index("pub fn status(&self) -> EngineStatus"):
        native_engine.index("pub fn scan_file")
    ]
    provider_inventory = provider[
        provider.index("pub fn builtin_provider_inventory"):
        len(provider)
    ]
    label_start = local_core.index("fn native_ml_status_label")
    label_helper = local_core[
        label_start:
        local_core.index("fn native_engine", label_start)
    ]
    rust_label_test = local_core[
        local_core.index("fn native_ml_status_label_uses_production_metadata_not_version_text"):
        local_core.index("fn display_file_name_uses_leaf_or_path_fallback")
    ]

    assert "pub ml_model_production_ready: bool" in status_struct
    assert "ml_model_production_ready: self.ml.production_ready()" in status_fn
    assert "self.ml.production_ready()," in status_fn
    assert '"native_ml_production_ready": status.ml_model_production_ready' in local_core
    assert (
        'body.insert("native_ml_production_ready".to_string(), json!(false))'
        in local_core
    )
    assert "if !status.ml_model_production_ready" in label_helper
    assert 'version.contains("dev")' not in label_helper
    assert "ml_production_ready: bool" in provider_inventory
    assert (
        "development ML model is loaded for review only; not production-ready"
        in provider_inventory
    )
    assert "Some(\"development ML model is unavailable\".to_string())" in provider_inventory
    assert "native_ml_status_label_uses_production_metadata_not_version_text" in rust_label_test
    assert 'Some("1.0.0"), false' in rust_label_test
    assert 'Some("0.1.0-dev"), true' in rust_label_test
    assert 'version.contains(\\"dev\\")' in rust_label_test


