def test_controller_update_events_are_categorized_by_outcome_severity():
    app_state = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "app_state.dart")
    start = app_state.index("Future<void> unawaitedCheckForUpdates")
    stop = app_state.index("bool _isUpdateOperationBusy")
    update_source = app_state[start:stop]

    for event_name in [
        "update_check_failed",
        "update_install_failed",
        "update_rollback_failed",
    ]:
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", update_source)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = update_source[occurrence:update_source.index(");", occurrence)]
            assert "category: 'update'" in event_source
            assert "severity: 'error'" in event_source

    for event_name in [
        "update_action_busy",
        "update_available",
        "update_install_started",
        "update_install_confirmation_required",
        "update_install_ready",
        "update_rollback_unavailable",
        "update_rollback_confirmation_required",
        "update_rollback_started",
        "update_rollback_ready",
    ]:
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", update_source)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = update_source[occurrence:update_source.index(");", occurrence)]
            assert "category: 'update'" in event_source
            assert "severity: 'warning'" in event_source

    for event_name in [
        "update_check_started",
        "update_check_completed",
    ]:
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", update_source)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = update_source[occurrence:update_source.index(");", occurrence)]
            assert "category: 'update'" in event_source
            assert "severity: 'info'" in event_source


