def test_flutter_update_package_download_streams_to_reserved_temp_file():
    update_service = read(UPDATE_SERVICE)
    update_service_test = read(
        ROOT / "apps" / "zentor_client" / "test" / "update_service_test.dart"
    )
    download_method = update_service[
        update_service.index("Future<UpdateInfo> downloadUpdatePackage"):
        update_service.index("Future<http.StreamedResponse> _getPackageWithAllowedRedirects")
    ]
    stream_writer = update_service[
        update_service.index("Future<void> _writeStreamToReservedPackageFile"):
        update_service.index("Future<void> _deleteTemporaryPackageFile")
    ]
    redirect_sender = update_service[
        update_service.index("Future<http.StreamedResponse> _sendWithAllowedGithubReleaseRedirects"):
        update_service.index("Uri _allowedGithubReleaseRedirectLocation")
    ]

    assert "_writeStreamToReservedPackageFile" in download_method
    assert "response.stream" in download_method
    assert "response.bodyBytes" not in download_method
    assert "await for (final chunk in stream.timeout(_networkReadTimeout))" in stream_writer
    assert "_rejectOversizedPackage(totalBytes, label)" in stream_writer
    assert "await output.writeFrom(chunk)" in stream_writer
    assert "on TimeoutException" in stream_writer
    assert "$label download timed out." in stream_writer
    assert "Future<http.StreamedResponse> _getPackageWithAllowedRedirects" in update_service
    assert "Future<http.StreamedResponse> _sendWithAllowedGithubReleaseRedirects" in update_service
    assert "return streamed;" in redirect_sender
    assert "await _drainBoundedRedirectBody(streamed.stream, label)" in redirect_sender
    assert "const int maxUpdateRedirectBodyBytes = 64 * 1024" in update_service
    assert "Future<void> _drainBoundedRedirectBody" in update_service
    assert "totalBytes > maxUpdateRedirectBodyBytes" in update_service
    assert "redirect response body is too large" in update_service
    assert "drain<void>()" not in redirect_sender
    assert "_writeBytesToReservedPackageFile" not in update_service
    assert (
        "failed local package staging preserves existing cached package"
        in update_service_test
    )
    assert "maxPackageBytes: 4" in update_service_test
    assert "service.downloadUpdatePackage(update)" in update_service_test
    assert "contains('Local update package source exceeds')" in update_service_test
    assert "expect(await cachedPackage.readAsString(), 'existing cached package')" in update_service_test
    assert "path.contains('.part')" in update_service_test
    assert "expect(leftovers, isEmpty)" in update_service_test


