def test_controller_scheduled_scan_and_heartbeat_events_are_categorized():
    app_state = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "app_state.dart")
    scheduled_settings_start = app_state.index("Future<bool> updateScheduledQuickScanSettings")
    scheduled_settings = app_state[
        scheduled_settings_start:
        app_state.index("void _configureScheduledQuickScan", scheduled_settings_start)
    ]
    scheduled_run = app_state[
        app_state.index("Future<void> _runScheduledQuickScan"):
        app_state.index("List<String> _normalizeUserPaths")
    ]
    heartbeat = app_state[
        app_state.index("Future<void> sendHeartbeat"):
        app_state.index("Future<void> scanSelectedFile")
    ]

    changed_start = scheduled_settings.index("'scheduled_quick_scan_settings_changed'")
    changed_event = scheduled_settings[
        changed_start:
        scheduled_settings.index("state = state.copyWith(", changed_start)
    ]
    assert "category: 'scan'" in changed_event
    assert "severity: 'warning'" in changed_event

    started_start = scheduled_run.index("'scheduled_quick_scan_started'")
    started_event = scheduled_run[started_start:scheduled_run.index(");", started_start)]
    assert "category: 'scan'" in started_event
    assert "final scheduledScanDiagnostic" in scheduled_run
    assert "state.lastEngineError?.trim().isEmpty ?? true" in scheduled_run
    assert "Engine diagnostics require attention:" in scheduled_run
    assert "details: scheduledScanDiagnostic" in started_event
    assert "severity: scheduledScanDiagnostic == null ? 'info' : 'warning'" in started_event
    assert scheduled_run.index("final scheduledScanDiagnostic") < scheduled_run.index(
        "'scheduled_quick_scan_started'"
    )

    sent_start = heartbeat.index("'heartbeat_sent'")
    sent_event = heartbeat[sent_start:heartbeat.index(");", sent_start)]
    assert "category: 'protection'" in sent_event
    assert "severity: 'info'" in sent_event

    failed_start = heartbeat.index("'heartbeat_failed'")
    failed_event = heartbeat[failed_start:heartbeat.index(");", failed_start)]
    assert "category: 'protection'" in failed_event
    assert "severity: 'warning'" in failed_event


