def test_cloud_api_request_models_reject_unknown_top_level_fields():
    models = read(API_SERVICE_MODELS)

    event_start = models.index("pub enum SecurityEventRequest")
    event_prefix = models[models.rindex("#[derive(Debug, Deserialize)]", 0, event_start):event_start]
    assert '#[serde(tag = "event_type", rename_all = "snake_case", deny_unknown_fields)]' in event_prefix
    assert "FileScanEvent { payload: Value }" in models
    assert "ServiceHealthEvent { payload: Value }" in models

    for struct_name in [
        "CreateProjectRequest",
        "RegisterDeviceRequest",
        "CreateSessionRequest",
        "HeartbeatRequest",
        "DetectionReportRequest",
        "DetectionReportItem",
        "QuarantineMetadataRequest",
        "CreateBanRequest",
    ]:
        struct_start = models.index(f"pub struct {struct_name}")
        derive_start = models.rindex("#[derive(Debug, Deserialize)]", 0, struct_start)
        model_prefix = models[derive_start:struct_start]
        assert "#[serde(deny_unknown_fields)]" in model_prefix


