def test_flutter_cloud_json_responses_are_bounded_while_streaming():
    source = read(API_CLIENT)
    api_client_test = read(ROOT / "apps" / "zentor_client" / "test" / "api_client_test.dart")
    transport_source = source[
        source.index("Future<http.Response> _sendCloudRequest"):
        source.index("Object? _decodeCloudJsonResponse")
    ]
    decoder_source = source[
        source.index("Object? _decodeCloudJsonResponse"):
        source.index("ApiResult<void>? _validateHealthAck")
    ]

    assert "static const _maxCloudJsonResponseBytes = 256 * 1024" in source
    assert "static const _cloudResponseReadTimeout = Duration(seconds: 10)" in source
    assert "int maxJsonResponseBytes = _maxCloudJsonResponseBytes" in source
    assert "Duration cloudResponseReadTimeout = _cloudResponseReadTimeout" in source
    assert "_requirePositiveCloudByteLimit" in source
    assert "_requirePositiveCloudTimeout" in source
    assert "_httpClient.send(request).timeout(requestTimeout)" in transport_source
    assert "streamed.stream.timeout(" in transport_source
    assert "_cloudResponseReadTimeoutValue" in transport_source
    assert "totalBytes += chunk.length" in transport_source
    assert "totalBytes > _maxJsonResponseBytes" in transport_source
    assert "_rejectOversizedCloudJsonHeader" in transport_source
    assert "http.Response.bytes(" in transport_source
    assert "_httpClient.get(" not in source
    assert "_httpClient.post(" not in source
    assert "response.bodyBytes.length" not in source
    assert "jsonDecode(response.body)" in decoder_source
    assert "cloud JSON responses are size bounded" in api_client_test
    assert "API client rejects oversized streamed cloud health responses" in api_client_test
    assert "API client fails cloud health when response stream stalls" in api_client_test
    assert "streamed.stream.timeout(" in api_client_test
    assert "response.bodyBytes.length" in api_client_test
    assert "isNot(contains('response.bodyBytes.length'))" in api_client_test


