def test_client_route_matrix_navigation_is_widget_verified():
    router = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "router.dart")
    sidebar = read(
        ROOT / "apps" / "zentor_client" / "lib" / "shared" / "widgets" / "zentor_sidebar.dart"
    )
    bottom_nav = read(
        ROOT / "apps" / "zentor_client" / "lib" / "shared" / "widgets" / "zentor_bottom_nav.dart"
    )
    route_test = read(
        ROOT / "apps" / "zentor_client" / "test" / "route_matrix_test.dart"
    )
    doc = read(CLIENT_UI_DOC)
    navigation_matrix = doc[
        doc.index("## Navigation Matrix"):
        doc.index("The mobile bottom navigation intentionally exposes")
    ]
    privacy_row = doc[
        doc.index("| Settings | View privacy policy |"):
        doc.index("| Settings | Developer options switch |")
    ]

    for route in [
        "/home",
        "/scan",
        "/protection",
        "/quarantine",
        "/allowlist",
        "/logs",
        "/device",
        "/updates",
        "/settings",
        "/privacy",
        "/onboarding",
    ]:
        assert f"path: '{route}'" in router
    for label in [
        "Home",
        "Scan",
        "Protection",
        "Quarantine",
        "Allowlist",
        "Security Events",
        "Device",
        "Updates",
        "Settings",
    ]:
        assert f"'{label}'" in sidebar
    assert "destination.path == '/home'" in bottom_nav
    assert "destination.path == '/scan'" in bottom_nav
    assert "destination.path == '/quarantine'" in bottom_nav
    assert "destination.path == '/settings'" in bottom_nav
    assert "route matrix desktop sidebar navigates primary routes" in route_test
    assert "route matrix settings privacy link opens privacy route" in route_test
    assert "route matrix mobile bottom nav exposes primary workflows only" in route_test
    assert "ZentorShell(location: state.uri.path, child: child)" in route_test
    assert "NoTransitionPage(child: _RouteMarker(route))" in route_test
    assert "find.byTooltip('Open Protection'), findsNothing" in route_test
    assert "Widget/runtime route verified in checkpoint 1864" in navigation_matrix
    assert "Widget/runtime route verified in checkpoint 1864" in privacy_row


