def test_controller_settings_events_are_categorized():
    app_state = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "app_state.dart")
    slices = {
        "developer_cloud": app_state[
            app_state.index("Future<bool> saveDeveloperCloudOverride"):
            app_state.index("Future<void> unawaitedDetectApps")
        ],
        "export_logs": app_state[
            app_state.index("Future<String?> exportLogs"):
            app_state.index("Future<bool> resetConfiguration")
        ],
        "reset_configuration": app_state[
            app_state.index("Future<bool> resetConfiguration"):
            app_state.index("AppVerificationStatus _verificationStatusFor")
        ],
    }

    expected = [
        ("developer_cloud", "developer_cloud_override_confirmation_required", "warning"),
        ("developer_cloud", "developer_cloud_override_busy", "warning"),
        ("developer_cloud", "configuration_saved", "warning"),
        ("developer_cloud", "configuration_save_failed", "error"),
        ("export_logs", "logs_export_confirmation_required", "warning"),
        ("export_logs", "logs_export_busy", "warning"),
        ("export_logs", "logs_exported", "info"),
        ("export_logs", "logs_export_failed", "error"),
        ("reset_configuration", "configuration_reset_confirmation_required", "warning"),
        ("reset_configuration", "configuration_reset_busy", "warning"),
        ("reset_configuration", "configuration_reset", "warning"),
        ("reset_configuration", "configuration_reset_failed", "error"),
    ]
    for slice_name, event_name, severity in expected:
        source = slices[slice_name]
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", source)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = source[occurrence:source.index(");", occurrence)]
            assert "category: 'settings'" in event_source
            assert f"severity: '{severity}'" in event_source


