def test_controller_app_detection_and_malware_health_events_are_categorized():
    app_state = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "app_state.dart")
    offline_scan_test = read(
        ROOT / "apps" / "zentor_client" / "test" / "offline_scan_test.dart"
    )
    app_detection = app_state[
        app_state.index("Future<void> unawaitedDetectApps"):
        app_state.index("Future<void> unawaitedCheckMalwareEngine")
    ]
    malware_health = app_state[
        app_state.index("Future<void> unawaitedCheckMalwareEngine"):
        app_state.index("Future<void> unawaitedRefreshQuarantine")
    ]

    expected_app_detection = [
        ("app_detection_busy", "warning"),
        ("app_detection_disabled", "warning"),
        ("app_detection_started", "info"),
        ("no_supported_app_detected", "warning"),
        ("protected_app_detected", "info"),
        ("app_detection_failed", "error"),
    ]
    for event_name, severity in expected_app_detection:
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", app_detection)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = app_detection[occurrence:app_detection.index(");", occurrence)]
            assert "category: 'protection'" in event_source
            assert f"severity: '{severity}'" in event_source

    engine_event_start = malware_health.index("status == MalwareEngineStatus.available")
    engine_event_end = malware_health.index(");", engine_event_start)
    engine_event = malware_health[engine_event_start:engine_event_end]
    assert "category: 'protection'" in engine_event
    assert "final healthEventSeverity" in malware_health
    assert "status == MalwareEngineStatus.available && healthDetails.isEmpty" in malware_health
    assert "severity: healthEventSeverity" in engine_event
    health_event_start = malware_health.index("final healthEventSeverity")
    assert malware_health.index("final healthDetails") < malware_health.index(
        "final healthEventSeverity"
    ) < malware_health.index("await logEvent(", health_event_start)

    busy_start = malware_health.index("'malware_engine_health_busy'")
    busy_event = malware_health[busy_start:malware_health.index(");", busy_start)]
    assert "category: 'protection'" in busy_event
    assert "severity: 'warning'" in busy_event

    failed_start = malware_health.index("'malware_engine_health_failed'")
    failed_event = malware_health[failed_start:malware_health.index(");", failed_start)]
    assert "category: 'protection'" in failed_event
    assert "severity: 'error'" in failed_event

    assert (
        "startup protection readiness events keep category and outcome severity"
        in offline_scan_test
    )
    assert (
        "startup protection readiness failures are protection errors"
        in offline_scan_test
    )
    for marker in [
        "event.type == 'app_detection_started'",
        "event.type == 'process_snapshot_empty'",
        "event.type == 'no_supported_app_detected'",
        "event.type == 'malware_engine_available'",
        "event.type == 'app_detection_failed'",
        "event.type == 'malware_engine_health_failed'",
        "expect(detectionStarted.category, 'protection')",
        "expect(detectionStarted.severity, 'info')",
        "expect(snapshotEmpty.severity, 'warning')",
        "expect(noAppDetected.severity, 'warning')",
        "expect(engineAvailable.category, 'protection')",
        "expect(engineAvailable.severity, 'warning')",
        "expect(appDetectionFailed.severity, 'error')",
        "expect(healthFailed.severity, 'error')",
    ]:
        assert marker in offline_scan_test


