def test_controller_quarantine_and_allowlist_refreshes_are_queued_single_flight():
    app_state = read(APP_STATE)
    offline_scan_test = read(ROOT / "apps" / "zentor_client" / "test" / "offline_scan_test.dart")
    quarantine_screen = read(
        ROOT / "apps" / "zentor_client" / "lib" / "features" / "quarantine" / "quarantine_screen.dart"
    )
    allowlist_screen = read(
        ROOT / "apps" / "zentor_client" / "lib" / "features" / "allowlist" / "allowlist_screen.dart"
    )
    allowlist_test = read(
        ROOT / "apps" / "zentor_client" / "test" / "allowlist_screen_test.dart"
    )
    doc = read(CLIENT_UI_DOC)
    state_model = app_state[
        app_state.index("const ZentorState({"):
        app_state.index("class ZentorController")
    ]
    controller_fields = app_state[
        app_state.index("final ZentorUpdateService _updateService;"):
        app_state.index("Timer? _scheduledQuickScanTimer;")
    ]
    quarantine_refresh = app_state[
        app_state.index("Future<void> unawaitedRefreshQuarantine"):
        app_state.index("Future<void> unawaitedRefreshAllowlist")
    ]
    allowlist_refresh = app_state[
        app_state.index("Future<void> unawaitedRefreshAllowlist"):
        app_state.index("Future<void> startCoreService")
    ]
    quarantine_doc_row = doc[
        doc.index("| Quarantine | Refresh |"):
        doc.index("| Quarantine item | Restore / Keep |")
    ]
    allowlist_doc_row = doc[
        doc.index("| Allowlist | Refresh |"):
        doc.index("| Allowlist entry | Remove |")
    ]

    for name in [
        "_quarantineRefreshInFlight",
        "_quarantineRefreshPending",
        "_allowlistRefreshInFlight",
        "_allowlistRefreshPending",
    ]:
        assert f"bool {name} = false;" in controller_fields

    for public_name in [
        "quarantineRefreshInFlight",
        "allowlistRefreshInFlight",
    ]:
        assert f"this.{public_name} = false," in state_model
        assert f"final bool {public_name};" in state_model
        assert f"bool? {public_name}," in state_model
        assert f"{public_name} ?? this.{public_name}" in state_model

    for source, prefix, list_call, failure_event in [
        (
            quarantine_refresh,
            "_quarantineRefresh",
            "final quarantine = await _localCoreClient.listQuarantine();",
            "'quarantine_refresh_failed'",
        ),
        (
            allowlist_refresh,
            "_allowlistRefresh",
            "final allowlist = await _localCoreClient.listAllowlist();",
            "'allowlist_refresh_failed'",
        ),
    ]:
        in_flight = f"{prefix}InFlight"
        pending = f"{prefix}Pending"
        public_name = (
            "quarantineRefreshInFlight"
            if prefix == "_quarantineRefresh"
            else "allowlistRefreshInFlight"
        )
        assert f"if ({in_flight})" in source
        assert f"{pending} = true;" in source
        assert f"{in_flight} = true;" in source
        assert f"{public_name}: true" in source
        assert f"{public_name}: false" in source
        assert "do {" in source
        assert f"{pending} = false;" in source
        assert list_call in source
        assert failure_event in source
        assert f"}} while ({pending});" in source
        assert f"}} finally {{\n      {in_flight} = false;" in source
        assert source.index(f"if ({in_flight})") < source.index(f"{in_flight} = true;")
        assert source.index(f"{in_flight} = true;") < source.index(list_call)
        assert source.index(f"{pending} = false;") < source.index(list_call)
        assert source.index(f"}} finally {{") > source.index(f"}} while ({pending});")

    assert "final quarantineRefreshBusy = state.quarantineRefreshInFlight;" in quarantine_screen
    assert "label: quarantineRefreshBusy ? 'Refreshing' : 'Refresh'" in quarantine_screen
    assert "onPressed: quarantineActionBusy || quarantineRefreshBusy" in quarantine_screen
    assert "final allowlistRefreshBusy = state.allowlistRefreshInFlight;" in allowlist_screen
    assert "label: allowlistRefreshBusy ? 'Refreshing' : 'Refresh'" in allowlist_screen
    assert "onPressed: allowlistActionBusy || allowlistRefreshBusy" in allowlist_screen
    assert "allowlist refresh button calls local core once" in allowlist_test
    assert "int listAllowlistCalls = 0" in allowlist_test
    assert "expect(localCore.listAllowlistCalls, 1)" in allowlist_test
    assert "expect(localCore.listAllowlistCalls, 2)" in allowlist_test
    assert "expect(controller.state.allowlistRefreshInFlight, isFalse)" in allowlist_test
    assert "expect(find.text(entry.path), findsOneWidget)" in allowlist_test

    for doc_row in [quarantine_doc_row, allowlist_doc_row]:
        assert "queued single-flight refresh" in doc_row
        assert "avoids overlapping IPC" in doc_row
        assert "reruns if a request arrives while busy" in doc_row
        assert "disabled while refresh is in flight" in doc_row

    assert "quarantine refresh failure diagnostics are normalized and bounded" in offline_scan_test
    assert "allowlist refresh failure diagnostics are normalized and bounded" in offline_scan_test
    assert "start protection exception diagnostics are normalized at runtime" in offline_scan_test
    assert "scan cancellation exception diagnostics are normalized at runtime" in offline_scan_test
    assert "guard ipc denied\\x00\\n\\t" in offline_scan_test
    assert "cancel IPC unavailable\\x00\\n\\t" in offline_scan_test
    assert "expect(localCore.guardModeCalls, 1)" in offline_scan_test
    assert "expect(localCore.watchCalls, 0)" in offline_scan_test
    assert "expect(state.protectionStatus, ProtectionStatus.error)" in offline_scan_test
    assert "expect(localCore.cancelCalls, 1)" in offline_scan_test
    assert "expect(failedCancelState.scanStatus, ScanStatus.running)" in offline_scan_test
    assert "startsWith('Unable to request scan cancellation:')" in offline_scan_test
    assert "event.type == 'protection_start_failed'" in offline_scan_test
    assert "event.type == 'scan_cancel_failed'" in offline_scan_test
    assert "isNot(contains('\\x00'))" in offline_scan_test
    assert "isNot(contains('\\n\\t'))" in offline_scan_test
    assert "lessThanOrEqualTo(2200)" in offline_scan_test


def test_controller_protected_app_mutation_events_are_categorized():
    app_state = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "app_state.dart")
    slices = {
        "manual_file": app_state[
            app_state.index("Future<bool> addManualProtectedAppFile"):
            app_state.index("Future<bool> addManualProtectedAppFolder")
        ],
        "manual_folder": app_state[
            app_state.index("Future<bool> addManualProtectedAppFolder"):
            app_state.index("Future<bool> selectDetectedApp")
        ],
        "select_detected": app_state[
            app_state.index("Future<bool> selectDetectedApp"):
            app_state.index("Future<bool> _saveManualAppPath")
        ],
        "save_manual": app_state[
            app_state.index("Future<bool> _saveManualAppPath"):
            app_state.index("Future<bool> calculateProtectedAppHash")
        ],
        "hash": app_state[
            app_state.index("Future<bool> calculateProtectedAppHash"):
            app_state.index("Future<void> startProtection")
        ],
    }

    expected = [
        ("manual_file", "manual_protected_app_selection_confirmation_required", "warning"),
        ("manual_file", "manual_protected_app_file_unavailable", "warning"),
        ("manual_file", "manual_protected_app_file_failed", "error"),
        ("manual_folder", "manual_protected_app_selection_confirmation_required", "warning"),
        ("manual_folder", "manual_protected_app_folder_unavailable", "warning"),
        ("manual_folder", "manual_protected_app_folder_failed", "error"),
        ("select_detected", "protected_app_selection_confirmation_required", "warning"),
        ("select_detected", "protected_app_selected", "warning"),
        ("select_detected", "protected_app_select_failed", "error"),
        ("save_manual", "protected_app_added_manually", "warning"),
        ("hash", "protected_app_hash_confirmation_required", "warning"),
        ("hash", "protected_app_hash_no_target", "warning"),
        ("hash", "protected_app_hash_path_probe_failed", "error"),
        ("hash", "protected_app_hash_unavailable", "warning"),
        ("hash", "file_hash_calculated", "warning"),
        ("hash", "file_hash_failed", "error"),
    ]
    for slice_name, event_name, severity in expected:
        source = slices[slice_name]
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", source)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = source[occurrence:source.index(");", occurrence)]
            assert "category: 'protection'" in event_source
            assert f"severity: '{severity}'" in event_source


