def test_controller_quarantine_and_allowlist_events_are_categorized():
    app_state = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "app_state.dart")
    slices = {
        "quarantine_threat": app_state[
            app_state.index("Future<void> quarantineThreat"):
            app_state.index("Future<void> ignoreThreat")
        ],
        "add_allowlist": app_state[
            app_state.index("Future<void> addThreatToAllowlist"):
            app_state.index("Future<void> removeAllowlistEntry")
        ],
        "remove_allowlist": app_state[
            app_state.index("Future<void> removeAllowlistEntry"):
            app_state.index("Future<void> restoreQuarantineItem")
        ],
        "restore_quarantine": app_state[
            app_state.index("Future<void> restoreQuarantineItem"):
            app_state.index("Future<void> deleteQuarantineItem")
        ],
        "delete_quarantine": app_state[
            app_state.index("Future<void> deleteQuarantineItem"):
            app_state.index("void _replaceQuarantineRecordStatus")
        ],
    }

    expected = [
        ("quarantine_threat", "quarantine_failed", "quarantine", "error"),
        ("quarantine_threat", "file_quarantined", "quarantine", "warning"),
        ("add_allowlist", "allowlist_entry_add_failed", "protection", "error"),
        ("add_allowlist", "allowlist_entry_added", "protection", "warning"),
        ("remove_allowlist", "allowlist_entry_remove_failed", "protection", "error"),
        ("remove_allowlist", "allowlist_entry_removed", "protection", "warning"),
        ("restore_quarantine", "quarantine_restore_requested", "quarantine", "warning"),
        ("restore_quarantine", "quarantine_restore_failed", "quarantine", "error"),
        ("restore_quarantine", "quarantine_item_restored", "quarantine", "warning"),
        ("delete_quarantine", "quarantine_delete_failed", "quarantine", "error"),
        ("delete_quarantine", "quarantine_item_deleted", "quarantine", "warning"),
    ]
    for slice_name, event_name, category, severity in expected:
        source = slices[slice_name]
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", source)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = source[occurrence:source.index(");", occurrence)]
            assert f"category: '{category}'" in event_source
            assert f"severity: '{severity}'" in event_source


