def test_controller_detection_feedback_events_are_categorized():
    app_state = read(ROOT / "apps" / "zentor_client" / "lib" / "app" / "app_state.dart")
    slices = {
        "false_positive": app_state[
            app_state.index("Future<void> markThreatFalsePositive"):
            app_state.index("Future<void> markThreatMalicious")
        ],
        "malicious": app_state[
            app_state.index("Future<void> markThreatMalicious"):
            app_state.index("Future<void> addThreatToAllowlist")
        ],
    }

    expected = [
        ("false_positive", "false_positive_label_confirmation_required", "protection", "warning"),
        ("false_positive", "false_positive_label_failed", "protection", "error"),
        ("false_positive", "false_positive_label_saved", "protection", "warning"),
        ("malicious", "malicious_label_confirmation_required", "protection", "warning"),
        ("malicious", "malicious_label_failed", "protection", "error"),
        ("malicious", "malicious_label_saved", "protection", "warning"),
    ]
    for slice_name, event_name, category, severity in expected:
        source = slices[slice_name]
        occurrences = [match.start() for match in re.finditer(f"'{event_name}'", source)]
        assert occurrences, f"missing {event_name}"
        for occurrence in occurrences:
            event_source = source[occurrence:source.index(");", occurrence)]
            assert f"category: '{category}'" in event_source
            assert f"severity: '{severity}'" in event_source


