def test_guard_quarantine_staged_writes_are_final_destination_exclusive_and_cleanup_temps():
    guard = read(GUARD_MAIN)
    staged_source = guard[
        guard.index("fn write_staged_quarantine_file("):
        guard.index("fn write_file_exclusive")
    ]
    file_writer_source = guard[
        guard.index("fn write_file_exclusive"):
        guard.index("fn remove_existing_quarantine_file")
    ]
    write_sources = guard[
        guard.index("fn write_quarantine_record("):
        guard.index("fn read_bounded_guard_quarantine_text")
    ]
    destination_source = guard[
        guard.index("fn ensure_quarantine_file_destination_absent"):
        guard.index("fn constant_time_eq")
    ]
    marker_start = guard.index("fn guard_quarantine_staged_writes_reject_linked_temp_paths_in_source")
    marker_source = guard[
        marker_start:
        guard.index("fn guard_legacy_fixed_record_temp_link_is_not_used_by_uuid_staging", marker_start)
    ]

    first_parent_check = staged_source.index("ensure_quarantine_file_parent_directory(path, label)?")
    temp_allocation = staged_source.index("let temp_path = guard_quarantine_staged_temp_path(path, label)?")
    second_parent_check = staged_source.index(
        "if let Err(error) = ensure_quarantine_file_parent_directory(path, label)"
    )
    final_destination_check = staged_source.index(
        "if let Err(error) = ensure_quarantine_file_destination_absent(path, label)"
    )

    assert "let temp_path = guard_quarantine_staged_temp_path(path, label)?" in staged_source
    assert "write_file_exclusive(&temp_path, bytes, label)" in staged_source
    assert "fn guard_quarantine_staged_temp_path" in staged_source
    assert "temp_name.push(format!(\".tmp-{}\", Uuid::new_v4()))" in staged_source
    assert "ensure_quarantine_file_parent_directory(path, label)?" in staged_source
    assert "ensure_quarantine_file_parent_directory(path, label)" in staged_source
    assert "cleanup_guard_quarantine_staged_file(&temp_path, label)" in staged_source
    assert "ensure_quarantine_file_destination_absent(path, label)" in staged_source
    assert "remove_existing_quarantine_file(path, label)?" not in staged_source
    assert "remove_existing_quarantine_file(temp_path, label)?" not in staged_source
    write_error_source = staged_source[
        staged_source.index("write_file_exclusive(&temp_path, bytes, label)?;"):
        staged_source.index("if let Err(error) = reject_link_path(&temp_path, label)")
    ]
    assert "cleanup_guard_quarantine_staged_file" not in write_error_source
    assert "write_file_exclusive(&temp_path, bytes, label)?;" in write_error_source
    assert "let mut output = match fs::OpenOptions::new()" in file_writer_source
    assert "Err(error) => {" in file_writer_source
    assert "failed to create temporary {label}" in file_writer_source
    assert "cleanup_guard_quarantine_staged_file(path, label)" in file_writer_source
    assert "after write failure" in file_writer_source
    assert "after sync failure" in file_writer_source
    assert first_parent_check < temp_allocation
    assert second_parent_check < final_destination_check
    for fixed_temp in [
        'with_extension("json.tmp")',
        'with_extension("auth.tmp")',
        'base.join(".metadata_auth_key.tmp")',
    ]:
        assert fixed_temp not in write_sources
    for diagnostic in [
        "after temp validation failure",
        "after parent preflight failure",
        "after activation preflight failure",
        "after activation failure",
    ]:
        assert diagnostic in staged_source
    assert "fn cleanup_guard_quarantine_staged_file" in guard
    assert "fn ensure_quarantine_file_parent_directory" in guard
    assert "cleanup_guard_quarantine_partial_file(path, &cleanup_label)" in guard
    assert "{label} destination already exists" in destination_source
    assert "refusing to replace symbolic link {label}" in destination_source
    assert "refusing to replace reparse point {label}" in destination_source
    assert "refusing to replace non-file {label}" in destination_source
    assert "guard_quarantine_staged_writes_reject_existing_final_record" in guard
    assert "guard_quarantine_staged_writes_reject_existing_final_auth_sidecar" in guard
    assert "guard_legacy_fixed_record_temp_link_is_not_used_by_uuid_staging" in guard
    assert "guard_legacy_fixed_auth_temp_link_is_not_used_by_uuid_staging" in guard
    assert "guard_legacy_fixed_metadata_key_temp_link_is_not_used_by_uuid_staging" in guard
    assert "ensure_quarantine_file_parent_directory(path, label)" in marker_source
    assert "ensure_quarantine_file_destination_absent(path, label)" in marker_source
    assert "cleanup_guard_quarantine_staged_file(&temp_path, label)" in marker_source
    assert "old_final_replace_pattern" in marker_source


