def test_local_heuristic_auto_quarantine_requires_diverse_probable_evidence():
    source = read(LOCAL_HEURISTIC_PROVIDER)
    score_start = source.index("pub fn score_from_reasons")
    helper_start = source.index("pub fn eligible_for_heuristic_auto_quarantine")
    surface_start = source.index("fn should_surface_result")
    score_source = source[score_start:helper_start]
    helper_source = source[helper_start:surface_start]
    test_start = source.index(
        "fn heuristic_auto_quarantine_requires_probable_verdict_and_independent_sources"
    )
    test_end = source.index("fn obfuscated_script_detection_uses_bounded_sample")
    test_source = source[test_start:test_end]

    assert "fn high_quality_reason_count(reasons: &[RiskReason]) -> usize" in source
    assert "fn independent_reason_source_count(reasons: &[RiskReason]) -> usize" in source
    assert "let high_quality = high_quality_reason_count(&reasons);" in score_source
    assert "let independent_sources = independent_reason_source_count(&reasons);" in score_source
    assert "allowlisted || risk.verdict != RiskVerdict::ProbableMalware" in helper_source
    assert "risk.recommended_action == RecommendedAction::Quarantine" in helper_source
    assert "risk.engines_used.contains(&RiskEngine::Heuristic)" in helper_source
    assert "high_quality_reason_count(&risk.reasons) >= 3" in helper_source
    assert "independent_reason_source_count(&risk.reasons) >= 2" in helper_source
    assert "RiskVerdict::ConfirmedMalware" in test_source
    assert "RiskVerdict::Suspicious" in test_source
    assert "RecommendedAction::Review" in test_source
    assert "no_engine_evidence.engines_used = Vec::new();" in test_source
    assert "reason.source = RiskReasonSource::Heuristic;" in test_source


