def test_file_walker_error_caps_report_omissions():
    cases = [
        (
            read(LOCAL_FILE_WALKER),
            "MAX_WALK_ERROR_DETAILS",
            "MAX_WALK_ERROR_DETAIL_CHARS",
            "WALK_ERROR_TRUNCATION_SUFFIX",
            "bounded_walk_error_detail(&detail)",
            "walk_error_omission_notice()",
            "additional file-walk errors omitted after {MAX_WALK_ERROR_DETAILS} details",
            "walker_error_details_are_bounded_and_report_omissions",
        ),
        (
            read(NATIVE_FILE_WALKER),
            "MAX_NATIVE_WALK_ERROR_DETAILS",
            "MAX_NATIVE_WALK_ERROR_DETAIL_CHARS",
            "NATIVE_WALK_ERROR_TRUNCATION_SUFFIX",
            "bounded_native_walk_error_detail(&detail)",
            "native_walk_error_omission_notice()",
            "additional native file-walk errors omitted after {MAX_NATIVE_WALK_ERROR_DETAILS} details",
            "native_file_walker_error_details_are_bounded_and_report_omissions",
        ),
    ]
    for (
        source,
        max_details,
        max_chars,
        suffix,
        bounded_call,
        notice_call,
        notice_text,
        test_name,
    ) in cases:
        helper_start = source.index("fn push_walk_error")
        helper_end = source.index("fn is_")
        helper_source = source[helper_start:helper_end]
        assert f"const {max_details}: usize = 20;" in source
        assert f"const {max_chars}: usize = 4096;" in source
        assert f'const {suffix}: &str = "...[truncated]";' in source
        assert f"scan_errors.len() < {max_details}" in helper_source
        assert bounded_call in helper_source
        assert "} else if let Some(last)" in helper_source
        assert f"let notice = {notice_call};" in helper_source
        assert "if last != &notice" in helper_source
        assert "*last = notice;" in helper_source
        assert notice_text in helper_source
        assert "detail.replace('\\0', \"\\\\0\")" in helper_source
        assert ".chars().take(prefix_len).collect()" in helper_source
        assert ".push_str(" in helper_source
        assert test_name in source
        assert ".push(detail)" not in helper_source


