def test_sample_prefix_readers_use_explicit_chunk_limits():
    cases = [
        (
            read(LOCAL_HEURISTIC_PROVIDER),
            "fn read_bounded_sample(path: &Path, limit: u64)",
            "fn inspect_regular_heuristic_target",
            "inspect_regular_heuristic_target(path)?",
            "remaining = limit",
            "file.take(limit)",
        ),
        (
            read(LOCAL_YARA_PROVIDER),
            "fn read_bounded_sample(path: &Path)",
            "fn read_bounded_rule_text",
            "ensure_regular_yara_scan_file(path)?",
            "remaining = YARA_SAMPLE_LIMIT_BYTES",
            "file.take(YARA_SAMPLE_LIMIT_BYTES)",
        ),
        (
            read(GUARD_MAIN),
            "fn read_bounded_sample(path: &Path, limit: u64)",
            "fn read_bounded_guard_yara_rules",
            'regular_guard_file_metadata(path, "guard YARA scan target")?',
            "remaining = limit",
            "fs::File::open(path)?.take(limit)",
        ),
        (
            read(GUARD_DRIVER_IPC),
            "fn read_bounded_driver_yara_sample",
            "fn read_bounded_guard_yara_rules",
            "driver_scan_candidate_is_regular_file(path)?",
            "remaining = limit",
            "BufReader::new(File::open(path)?).take(limit)",
        ),
        (
            read(LOCAL_AI_FEATURE_EXTRACTOR),
            "fn read_static_feature_sample",
            "fn inspect_regular_static_feature_target",
            "inspect_regular_static_feature_target(path)?",
            "remaining = STATIC_FEATURE_SAMPLE_BYTES",
            "file.take(STATIC_FEATURE_SAMPLE_BYTES)",
        ),
    ]
    for source, start_marker, end_marker, metadata_guard, remaining, old_take in cases:
        reader = source[source.index(start_marker):source.index(end_marker)]

        assert metadata_guard in reader
        assert remaining in reader
        assert "let mut buffer = [0_u8; 8192]" in reader
        assert "read_limit = remaining.min(buffer.len() as u64) as usize" in reader
        assert "read(&mut buffer[..read_limit])" in reader
        assert "remaining -= read as u64" in reader
        assert "extend_from_slice(&buffer[..read])" in reader
        assert old_take not in reader
        assert "read_to_end" not in reader


