def test_driver_ipc_hash_read_errors_are_visible_in_verdict_reasons():
    ipc = read(ROOT / "core" / "zentor_guard_service" / "src" / "driver_ipc.rs")
    evaluate_start = ipc.index("let mut malformed_trusted_hash")
    publisher_start = ipc.index("if trusted_publisher(request, config)", evaluate_start)
    evaluate_source = ipc[evaluate_start:publisher_start]
    native_start = ipc.index("if let Some(native) = cached_native_engine_verdict", publisher_start)
    publisher_source = ipc[publisher_start:native_start]
    helper_start = ipc.index("fn hash_evidence_reason")
    helper_end = ipc.index("fn malformed_trusted_hash_result")
    helper_source = ipc[helper_start:helper_end]

    assert "let mut local_hash_error" in evaluate_source
    assert "let mut hash_from_trusted_metadata" in evaluate_source
    assert "Err(error) => {" in evaluate_source
    assert "local_hash_error = Some(format!(\"{error:#}\"))" in evaluate_source
    assert "hash_from_trusted_metadata = true" in evaluate_source
    assert "hash_evidence_reason(" in evaluate_source
    assert "hash_evidence_reason(" in publisher_source
    assert '"Valid trusted publisher signature."' in publisher_source
    old_fallback = "Err(_) => match " + "trusted_request_sha256"
    assert old_fallback not in evaluate_source
    assert "Local file hash was unavailable" in helper_source
    assert "trusted SHA-256 metadata was used instead" in helper_source
    assert "no local hash evidence was used" in helper_source
    assert "driver_hash_read_errors_are_visible_when_no_trusted_metadata" in ipc
    assert "trusted_publisher_reports_unreadable_local_hash" in ipc


