def test_guard_self_test_report_evidence_is_not_hardcoded_success():
    self_test = read(GUARD_SELF_TEST)
    run_start = self_test.index("pub fn run_self_test")
    run_end = self_test.index("fn write_self_test_fixture")
    run_source = self_test[run_start:run_end]

    assert '"Guard self-test handler"' in run_source
    assert "not installed Windows service evidence" in run_source
    assert '"Guard Service running"' not in run_source

    assert "let post_launch_fallback_verified =" in run_source
    assert "post_launch_fallback_verified: true" not in run_source
    assert "eicar_verdict.action == DriverVerdictAction::Block" in run_source
    assert "known_bad_verdict.action == DriverVerdictAction::Block" in run_source
    assert "lockdown_unknown_verdict.action == DriverVerdictAction::Block" in run_source
    assert "approved_unknown_verdict.action == DriverVerdictAction::Allow" in run_source
    assert "known_good_verdict.action == DriverVerdictAction::Allow" in run_source
    assert '"Post-launch verdict fallback"' in run_source

    assert "verdict_cache_ok: false" in run_source
    assert "verdict_cache_ok: true" not in run_source
    assert "let guard_handler_available = steps" in run_source
    assert 'step.name == "Guard self-test handler" && step.passed' in run_source
    assert (
        "let guard_service_ipc_ok = guard_handler_available && post_launch_fallback_verified"
        in run_source
    )
    assert "running: guard_handler_available" in run_source
    assert "ipc_ok: guard_service_ipc_ok" in run_source
    assert "running: true" not in run_source
    assert "ipc_ok: true" not in run_source
    assert "guard_self_test_handler_step_is_not_installed_service_evidence" in self_test
    assert "post_launch_fallback_verified_is_not_hardcoded_success" in self_test
    assert "verdict_cache_status_is_disabled_without_a_cache_check" in self_test
    assert "guard_service_legacy_status_fields_are_not_hardcoded_success" in self_test


