def test_driver_install_uninstall_reports_require_verified_command_evidence():
    minifilter_install = read(DRIVER.parent / "scripts" / "install-test-driver.ps1")
    minifilter_uninstall = read(DRIVER.parent / "scripts" / "uninstall-test-driver.ps1")
    process_install = read(
        ROOT / "core" / "zentor_windows_process_guard" / "scripts" / "install-test-driver.ps1"
    )
    process_uninstall = read(
        ROOT / "core" / "zentor_windows_process_guard" / "scripts" / "uninstall-test-driver.ps1"
    )

    assert "ConfirmDriverInstall" in minifilter_install
    assert "commandDiagnostics.testsigning_probe" in minifilter_install
    assert "commandDiagnostics.driver_install" in minifilter_install
    assert "commandDiagnostics.filter_load" in minifilter_install
    assert "commandDiagnostics.filter_query" in minifilter_install
    assert '$loaded = $commandDiagnostics.filter_query.output -match "ZentorAvFilter"' in minifilter_install
    assert "ZentorAvFilter was not listed after load" in minifilter_install
    assert "installed = $true" in minifilter_install
    assert "running = $loaded" in minifilter_install
    assert "installed = $false" in minifilter_install
    assert "running = $false" in minifilter_install

    assert "ConfirmDriverInstall" in process_install
    assert "commandDiagnostics.driver_install" in process_install
    assert "commandDiagnostics.service_start" in process_install
    assert "commandDiagnostics.service_query" in process_install
    assert 'output -notmatch "STATE\\s*:\\s*\\d+\\s+RUNNING"' in process_install
    assert "ZentorProcessGuard was not running after start" in process_install
    assert "installed = $true" in process_install
    assert "running = $true" in process_install
    assert "installed = $false" in process_install
    assert "running = $false" in process_install

    for uninstall_script, driver_name in (
        (minifilter_uninstall, "ZentorAvFilter"),
        (process_uninstall, "ZentorProcessGuard"),
    ):
        assert "ConfirmDriverUninstall" in uninstall_script
        assert "commandErrors.Count -gt 0" in uninstall_script
        assert f"sc delete {driver_name}" in uninstall_script
        assert "uninstalled = $true" in uninstall_script
        assert "uninstalled = $false" in uninstall_script
        assert "command_diagnostics = $commandDiagnostics" in uninstall_script

    for driver_report_script in (
        minifilter_install,
        minifilter_uninstall,
        process_install,
        process_uninstall,
    ):
        assert "errors = @(Get-AvoraxBoundedDiagnostic $_.Exception.Message 4096)" in driver_report_script
        assert "errors = @($_.Exception.Message)" not in driver_report_script

    report_scope_cases = [
        (
            minifilter_install,
            'Assert-AvoraxRepoChildPath $ReportPath $RepoRoot "minifilter install report"',
        ),
        (
            minifilter_uninstall,
            'Assert-AvoraxRepoChildPath $ReportPath $RepoRoot "minifilter uninstall report"',
        ),
        (
            process_install,
            'Assert-AvoraxRepoChildPath $ReportPath $RepoRoot "process guard install report"',
        ),
        (
            process_uninstall,
            'Assert-AvoraxRepoChildPath $ReportPath $RepoRoot "process guard uninstall report"',
        ),
    ]
    for source, child_marker in report_scope_cases:
        guard_source = source[
            source.index("function Assert-AvoraxRepoChildPath"):
            source.index('Assert-AvoraxNoReparsePath $ReportPath')
        ]
        report_source = source[
            source.index('Assert-AvoraxNoReparsePath $ReportPath'):
            source.index("$setupScript = Get-AvoraxRegularFile")
        ]

        assert "$pathFull.Equals($baseFull" in guard_source
        assert "not the repository root itself" in guard_source
        assert "Assert-AvoraxPathUnder $pathFull $Base $DisplayName" in guard_source
        assert child_marker in report_source
        assert report_source.index(child_marker) < report_source.index(
            "$ReportDir = New-AvoraxRegularDirectory"
        )


