def test_update_package_excludes_driver_and_self_overwriting_update_service():
    builder = read(ROOT / "tools" / "update" / "avorax-build-update-package.ps1")
    hash_source = builder[
        builder.index("$hashes = [ordered]@{"):
        builder.index("$appPayloadFiles = @(")
    ]
    app_file_staging_source = builder[
        builder.index('$payloadSourceFilesRoot = Require-Directory $payloadSource "Payload root before top-level file staging"'):
        builder.index('$payloadSourceDirectoriesRoot = Require-Directory $payloadSource "Payload root before top-level directory staging"')
    ]
    app_directory_staging_source = builder[
        builder.index('$payloadSourceDirectoriesRoot = Require-Directory $payloadSource "Payload root before top-level directory staging"'):
        builder.index("$payloadSourceEngine = Join-Path $payloadSource")
    ]
    assert "driver-tools" in builder
    assert '$serviceFiles = @("avorax_core_service.exe", "avorax_guard_service.exe")' in builder
    assert 'Join-Path $payloadServices $name' in builder
    assert '$payloadSourceServicesRoot = Require-Directory $payloadSource "Payload root before service payload staging"' in builder
    assert 'Assert-NoReparseTree $payloadSourceServicesRoot "Payload root before service payload staging"' in builder
    assert '$payloadSourceUpdateService = Join-Path $payloadSourceServicesRoot "avorax_update_service.exe"' in builder
    assert 'Get-Item -LiteralPath ([System.IO.Path]::GetFullPath($payloadSourceUpdateService)) -Force -ErrorAction Stop' in builder
    assert 'Get-ChildItem -LiteralPath $payloadSourceServicesRoot -Directory -ErrorAction Stop' in builder
    assert "Normal .aup update package must not include avorax_update_service.exe because the updater cannot overwrite itself while running" in builder
    assert '$source = Join-Path $payloadSourceServicesRoot $name' in builder
    assert 'Assert-NoReparseTree $payloadSource "Payload root before service payload staging"' not in builder
    assert '$source = Join-Path $payloadSource $name' not in builder
    assert '$sourceFile = Require-File $source "service payload $name"' in builder
    assert '$destinationFile = Join-Path $payloadServices $name' in builder
    assert 'Assert-NoReparsePath $destinationFile "service payload destination $name"' in builder
    assert "Copy-Item -LiteralPath $sourceFile -Destination $destinationFile -Force" in builder
    assert 'Copy-Item -LiteralPath (Require-File $source "service payload $name") -Destination (Join-Path $payloadServices $name) -Force' not in builder
    assert '$payloadSourceFilesRoot = Require-Directory $payloadSource "Payload root before top-level file staging"' in app_file_staging_source
    assert 'Assert-NoReparseTree $payloadSourceFilesRoot "Payload root before top-level file staging"' in app_file_staging_source
    assert "Get-ChildItem -LiteralPath $payloadSourceFilesRoot -File -ErrorAction Stop" in app_file_staging_source
    assert 'Assert-NoReparseTree $payloadSource "Payload root before top-level file staging"' not in app_file_staging_source
    assert "Get-ChildItem -LiteralPath $payloadSource -File -ErrorAction Stop" not in app_file_staging_source
    assert '$payloadSourceDirectoriesRoot = Require-Directory $payloadSource "Payload root before top-level directory staging"' in app_directory_staging_source
    assert 'Assert-NoReparseTree $payloadSourceDirectoriesRoot "Payload root before top-level directory staging"' in app_directory_staging_source
    assert "Get-ChildItem -LiteralPath $payloadSourceDirectoriesRoot -Directory -ErrorAction Stop" in app_directory_staging_source
    assert 'Assert-NoReparseTree $payloadSource "Payload root before top-level directory staging"' not in app_directory_staging_source
    assert "Get-ChildItem -LiteralPath $payloadSource -Directory -ErrorAction Stop" not in app_directory_staging_source
    assert "$payloadSourceTools = Join-Path $payloadSource \"tools\"" in builder
    assert "Normal .aup update package must not include tools payloads" in builder
    assert "$payloadSourceMigrations = Join-Path $payloadSource \"migrations\"" in builder
    assert "Normal .aup update package must not include migration payloads" in builder
    assert "$payloadSourceDriver = Join-Path $payloadSource \"driver\"" in builder
    assert "Normal .aup update package must not include driver payloads" in builder
    assert "$payloadSourceDriverTools = Join-Path $payloadSource \"driver-tools\"" in builder
    assert "Normal .aup update package must not include driver-tools payloads" in builder
    assert 'Copy-NormalUpdateEnginePayload $payloadSourceEngine $payloadEngine' in builder
    assert "$payloadSourceDocs = Join-Path $payloadSource \"docs\"" in builder
    assert "Copy-NormalUpdateDocsPayload $payloadSourceDocs $payloadDocs" in builder
    assert 'foreach ($dir in @("docs"))' not in builder
    assert 'foreach ($dir in @("engine", "docs"))' not in builder
    assert 'foreach ($dir in @("engine", "docs", "tools"))' not in builder
    assert '$script:NormalUpdateEnginePayloadComponents = @("signatures", "rules", "ml", "trust")' in builder
    assert '$script:NormalUpdateEngineSourcePrunedChildren = @("config", "test_corpus", "threat_intel")' in builder
    assert "Normal .aup update package leaked unsupported engine payload path" in builder
    assert "Normal .aup update package engine payload file must be under an explicit runtime subdirectory" in builder
    assert '$payloadHashRoot = Require-Directory $payload "payload hash root"' in hash_source
    assert "$payloadFilesForHash = @(Get-RegularPayloadFiles $payloadHashRoot)" in hash_source
    assert "$payloadFilesForHash | ForEach-Object" in hash_source
    assert '$relative = $_.FullName.Substring($payloadHashRoot.Length).TrimStart("\\", "/").Replace("\\", "/")' in hash_source
    assert "$payloadFilesForHash = @(Get-RegularPayloadFiles $payload)" not in hash_source
    assert '$relative = $_.FullName.Substring($payload.Length).TrimStart("\\", "/").Replace("\\", "/")' not in hash_source
    assert "Get-ChildItem -LiteralPath $payload -Recurse -File -ErrorAction Stop" not in hash_source
    assert '$payloadFile = Require-File $_.FullName "payload file before hashing"' in builder
    assert "Get-FileHash -LiteralPath $payloadFile -Algorithm SHA256" in builder
    assert "Get-FileHash -LiteralPath $_.FullName -Algorithm SHA256" not in builder
    assert "Normal .aup update package leaked tools payload path" in builder
    assert "Normal .aup update package leaked migration payload path" in builder
    assert "Normal .aup update package app payload leaked restricted install path" in builder
    assert "Normal .aup update package app payload leaked managed service or updater executable" in builder
    assert 'Require-File $_.FullName "app payload file $($_.Name)"' in builder
    assert '$destinationFile = Join-Path $payloadApp $_.Name' in builder
    assert 'Assert-NoReparsePath $destinationFile "app payload destination file $($_.Name)"' in builder
    assert "Copy-Item -LiteralPath $sourceFile -Destination $destinationFile -Force" in builder
    assert 'Copy-Item -LiteralPath (Require-File $_.FullName "app payload file $($_.Name)") -Destination (Join-Path $payloadApp $_.Name) -Force' not in builder
    assert 'Copy-Item -LiteralPath $_.FullName -Destination (Join-Path $payloadApp $_.Name) -Force' not in builder
    assert 'Require-Directory $_.FullName "app payload directory $($_.Name)"' in builder
    assert 'Assert-NoReparsePath $destinationDirectory "app payload destination directory $($_.Name)"' in builder
    assert 'Assert-NoReparseTree $sourceDirectory "app payload directory $($_.Name) before recursive copy"' in builder
    assert 'Normal .aup update package app payload directory must not be named managed service or updater executable' in builder
    assert "Copy-Item -LiteralPath $sourceDirectory -Destination $destinationDirectory -Recurse -Force" in builder
    assert 'Copy-Item -LiteralPath $_.FullName -Destination (Join-Path $payloadApp $_.Name) -Recurse -Force' not in builder
    assert "driver_update_included = $false" in builder
    assert "avorax_update_service.exe" in builder
    assert "CreateEntryFromFile" in builder
    assert "Write-Utf8NoBomAtomic" in builder
    assert "$signer = @(Split-SignerCommand $SignerCommand)" in builder
    # Existing updater compatibility: do not use Compress-Archive because it writes backslash entries.
    assert "Compress-Archive" not in re.sub(r"#.*", "", builder)


