def test_update_manifest_scalar_fields_reject_raw_control_before_trim():
    manifest = read(ROOT / "core" / "avorax_update_service" / "src" / "update_manifest.rs")
    validate_static = manifest[
        manifest.index("pub fn validate_static_fields"):
        manifest.index("#[cfg(test)]")
    ]
    production_helpers = manifest[manifest.rindex("fn validate_manifest_scalar_text"):]
    helper = production_helpers[
        production_helpers.index("fn validate_manifest_scalar_text"):
        production_helpers.index("pub fn is_sha256")
    ]
    safe_token = production_helpers[
        production_helpers.index("fn validate_safe_token"):
        production_helpers.index("pub(crate) fn validate_version")
    ]
    version = production_helpers[
        production_helpers.index("pub(crate) fn validate_version"):
        production_helpers.index("fn validate_release_date")
    ]
    release_date = production_helpers[
        production_helpers.index("fn validate_release_date"):
        production_helpers.index("fn validate_release_notes_url")
    ]
    release_notes = production_helpers[
        production_helpers.index("fn validate_release_notes_url"):
        production_helpers.index("fn validate_optional_sha256")
    ]
    optional_sha = production_helpers[
        production_helpers.index("fn validate_optional_sha256"):
        production_helpers.index("fn validate_migration_steps")
    ]

    assert "validate_optional_sha256(&self.package_sha256, \"manifest package_sha256\")?" in validate_static
    assert "fn validate_manifest_scalar_text" in helper
    assert "value: &'a str" in helper
    assert "label: &str" in helper
    assert "anyhow::Result<&'a str>" in helper
    assert "value.chars().any(|ch| ch.is_control())" in helper
    assert "let trimmed = value.trim();" in helper
    assert "value == trimmed" in helper
    assert helper.index("value.chars().any(|ch| ch.is_control())") < helper.index(
        "let trimmed = value.trim();"
    )
    assert "validate_manifest_scalar_text(value, label)?" in safe_token
    assert "validate_manifest_scalar_text(value, label)?" in version
    assert "validate_manifest_scalar_text(value, \"manifest release_date\")?" in release_date
    assert "validate_manifest_scalar_text(value, \"manifest release_notes_url\")?" in release_notes
    assert "validate_manifest_scalar_text(value, label)?" in optional_sha
    assert "manifest_scalar_fields_reject_surrounding_whitespace" in manifest
    assert "manifest_scalar_fields_reject_raw_control_characters_before_trim" in manifest
    assert "manifest_package_sha256_rejects_whitespace_wrapped_hash" in manifest
    assert "update_manifest_scalar_validation_checks_raw_text_before_trim" in manifest


