    production = package.split("#[cfg(test)]")[0]
    extraction_source = production[
        production.index("pub fn extract_payload_to"):
        production.index("fn cleanup_extraction_temp_file")
    ]
    activation_source = production[
        production.index("fn activate_extracted_payload_file"):
        production.index("fn cleanup_extraction_temp_file")
    ]

    assert "activate_extracted_payload_file(&temp_target, &target, &destination)" in extraction_source
    assert (
        "fn activate_extracted_payload_file(\n        temp_target: &Path,\n        target: &Path,\n        destination: &Path,"
        in activation_source
    )
    assert "ensure_extraction_temp_file_ready(temp_target)?" in activation_source
    assert "ensure_existing_path_chain_not_link(" in activation_source
    assert 'parent,\n                destination,\n                "payload extraction destination"' in activation_source
