    assert activation_source.index("ensure_existing_path_chain_not_link(") < (
        activation_source.index("std::fs::rename(temp_target, target)")
    )
    assert activation_source.index(
        "ensure_payload_extraction_target_absent(target)?"
    ) < activation_source.index("std::fs::rename(temp_target, target)")
    assert "fn ensure_extraction_temp_file_ready(path: &Path) -> Result<()>" in activation_source
    assert (
        'ensure_not_link_or_reparse(path, "payload extraction temporary file")?'
        in activation_source
    )
    assert "metadata.is_file()" in activation_source
    assert "payload_activation_rechecks_target_before_rename" in package
    assert "payload_activation_rechecks_parent_chain_before_rename" in package
    assert "payload_activation_rechecks_temp_file_type_before_rename" in package


