def test_update_apply_and_rollback_install_dirs_reject_unsafe_text_before_creation():
    for path, regression in [
        (UPDATE_APPLIER, "update_apply_install_dir_rejects_unsafe_text_before_creation"),
        (UPDATE_ROLLBACK, "rollback_install_dir_rejects_unsafe_text_before_creation"),
    ]:
        source = read(path)
        production = source.split("#[cfg(test)]")[0]
        start = production.index("fn canonical_install_dir")
        if "fn canonical_snapshot_dir" in production[start:]:
            end = production.index("fn canonical_snapshot_dir", start)
        else:
            end = production.index("fn safe_update_id", start)
        install_source = production[start:end]

        assert "validate_install_dir_path_text(install_dir)?" in install_source
        assert install_source.index(
            "validate_install_dir_path_text(install_dir)?"
        ) < install_source.index("create_dir_all_checked(install_dir")
        assert "fn validate_install_dir_path_text(path: &Path) -> Result<()>" in install_source
        assert "path.as_os_str().to_string_lossy()" in install_source
        assert "install directory contains NUL" in install_source
        assert "install directory must not contain parent traversal" in install_source
        assert "fn install_dir_path_has_parent_traversal(path: &Path) -> bool" in install_source
        assert "matches!(component, Component::ParentDir)" in install_source
        if path == UPDATE_APPLIER:
            assert (
                "fn ensure_existing_install_directory(path: &Path, label: &str) -> Result<()>"
                in install_source
            )
            assert "std::fs::symlink_metadata(path)" in install_source
            assert "metadata.is_dir()" in install_source
            assert (
                'ensure_existing_install_directory(&canonical, "canonical install directory")?'
                in install_source
            )
        if path == UPDATE_ROLLBACK:
            assert (
                "fn ensure_existing_install_directory(path: &Path, label: &str) -> Result<()>"
                in install_source
            )
            assert "std::fs::symlink_metadata(path)" in install_source
            assert "metadata.is_dir()" in install_source
            assert (
                'ensure_existing_install_directory(&canonical, "canonical rollback install directory")?'
                in install_source
            )
            restore_source = production[
                production.index("pub fn restore_snapshot"):
                production.index("fn ensure_required_item")
            ]
            assert (
                'ensure_existing_install_directory(&install_dir, "rollback install directory before restore")?'
                in restore_source
            )
            assert restore_source.index(
                'ensure_existing_install_directory(&install_dir, "rollback install directory before restore")?'
            ) < restore_source.index("for item in ROLLBACK_ITEMS")
            assert "restore_revalidates_install_root_before_copying_items" in source
        assert regression in source


