def test_release_source_text_scans_use_shared_bounded_handle_reader():
    dependency = read(DEPENDENCY_EVIDENCE)
    zne = read(ZNE_RELEASE_GATE)
    windows_release = read(WINDOWS_RELEASE_GATE)
    stage = read(WINDOWS_INSTALLER_STAGE_TEST)

    assert "Read-AvoraxGateTextFileBounded $wrapperPath $maxTextFileBytes \"Gradle wrapper properties\"" in dependency
    assert "function New-LockfileSummary" in dependency
    assert "lockfile_summaries = $lockfileSummaries" in dependency
    assert "license_inventory = $licenseInventory" in dependency
    assert "full_release_sbom_required = $true" in dependency
    assert "machine_wide_dependency_installation = $false" in dependency
    assert "network_access_required = $false" in dependency
    assert "Read-AvoraxGateTextFileBounded $fullPath $maxTextFileBytes \"$Ecosystem lockfile $Lockfile\"" in dependency
    assert "Get-Content -LiteralPath $wrapperPath -Raw" not in dependency

    ui_start = zne.index("$badPattern =")
    ui_end = zne.index("$status = @{")
    ui_source = zne[ui_start:ui_end]
    assert "Read-AvoraxGateTextFileBounded $file.FullName $maxJsonBytes \"Flutter UI source file\"" in ui_source
    assert "Get-Content -LiteralPath $file.FullName -Raw" not in ui_source

    update_start = windows_release.index("$appUpdateService =")
    update_end = windows_release.index("$stage = Join-Path")
    update_source = windows_release[update_start:update_end]
    assert "Read-AvoraxGateTextFileBounded $appUpdateServiceFile $maxJsonBytes \"Flutter update service source\"" in update_source
    assert "Get-Content -Raw -LiteralPath $appUpdateServiceFile" not in update_source

    wxs_start = stage.index("$wxsFiles =")
    wxs_end = stage.index("if ($errors.Count -gt 0)")
    wxs_source = stage[wxs_start:wxs_end]
    assert "Read-AvoraxGateTextFileBounded $wxs.FullName $maxJsonBytes \"installer WiX source\"" in wxs_source
    assert "Get-Content -Raw -LiteralPath $wxs.FullName" not in wxs_source


