    assert "unawaited(" in wrapper
    assert "task().catchError((Object error) async" in wrapper
    assert "_boundedUiDiagnostic(error)" in wrapper
    assert "await logEvent(" in wrapper
    assert "'${type}_startup_failed'" in wrapper
    assert "severity: 'error'" in wrapper
