    update_applier = read(
        ROOT / "core" / "avorax_update_service" / "src" / "update_applier.rs"
    )

    assert "fn test_env_lock() -> std::sync::MutexGuard<'static, ()>" in main
    assert "static LOCK: std::sync::OnceLock<std::sync::Mutex<()>>" in main
